/* Linker version script for vadrv_shim.so
 *
 * vaGetDriverName and vaGetDeviceID are both exported under VA_API_1.15.0 to
 * match the versioned symbols in libva.so.2. Without matching version nodes,
 * glibc's dynamic linker will not use unversioned LD_PRELOAD symbols to
 * satisfy versioned symbol requirements.
 *
 * dlopen is exported unversioned so it overrides glibc's dlopen.
 */
VA_API_1.15.0 {
    global: vaGetDriverName; vaGetDeviceID;
};
